import { Placement } from '@floating-ui/react';
import type { ReactNode } from 'react';
import type { TestComponentProps } from '../../types/test-component';
export interface TooltipProps extends TestComponentProps {
    /**
     * Заголовок
     */
    title: ReactNode;
    /**
     * Отключает отображение при событии наведения курсора
     */
    disableHover?: boolean;
    /**
     * Режим отображения: по наведению, по клику или оба.
     * @default 'hover'
     */
    triggerMode?: 'hover' | 'click' | 'both';
    /**
     * Режим закрытия тултипа
     * - 'auto': закрывается при клике вне тултипа или по триггеру (по умолчанию)
     * - 'manual': закрывается только программно через open={false}
     * - 'content-click': закрывается при клике по содержимому тултипа
     * - 'outside-click': закрывается только при клике вне тултипа
     * @default 'auto'
     */
    closeMode?: 'auto' | 'manual' | 'content-click' | 'outside-click';
    /**
     * Пользовательский класс для содержимого компонента Tooltip.
     */
    className?: string;
    /**
     * Пользовательский класс для обертки над компонентом Tooltip.
     */
    popoverRootClassName?: string;
    /**
     * Пользовательский класс для добавления класса порталу.
     */
    portalClassName?: string;
    /**
     * Состояние отображения: отображено / скрыто.
     */
    open?: boolean;
    /**
     * Длительность анимации появления/скрытия (в мс).
     * Может быть числом (для обоих) или объектом { enter, exit }.
     * @default { enter: 400, exit: 200 }
     */
    transitionDuration?: number | {
        enter: number;
        exit: number;
    };
    children?: React.JSX.Element;
    /**
     * Прикреплять портал к children вместо root
     * @default false
     */
    attachToChildren?: boolean;
    'aria-describedby'?: string;
    /**
     * Положение поповера относительно якорного элемента (children)
     * Совместимо с floating-ui: 'top', 'bottom', 'left', 'right' и варианты '-start'/'-end'
     * @default 'bottom'
     */
    placement?: Placement;
}
